const result = {
  experiment: 'balanced_population_assumption_50_50',
  title: 'ChurnRadar 50:50 균형 가정 실험 결과',
  assumption_note: '전체 이탈 고객 549명과 동일한 수의 비이탈 고객 549명을 무작위 추출하여 이탈/비이탈 50:50 평가 환경을 만든 가정 실험입니다.',
  caveat: '이 결과는 실제 운영 분포가 아니라 50:50 균형 가정에서만 유효합니다. 실제 Baza 원본 분포의 이탈률은 약 6.5%입니다.',
  dataset: {
    source: 'Baza Telecom v2 B2B CRM',
    rows: 8453,
    churn_count: 549,
    non_churn_count: 7904,
    original_churn_rate: 0.06494735596829528,
    balanced_sample_rows: 1098,
    balanced_churn_rate: 0.5,
    balanced_sample_fraction_of_original: 0.12989471193659055
  },
  model: {
    name: 'RandomForest_balanced',
    threshold: 0.30705154557360087
  },
  metrics_50_50: {
    f1_score: 0.6666666666666666,
    recall: 0.990909090909091,
    precision: 0.5023041474654378,
    roc_auc: 0.5452892561983472,
    average_precision: 0.5386199095476428,
    confusion_matrix: {
      tn: 2,
      fp: 108,
      fn: 1,
      tp: 109
    },
    predicted_positive_rate: 0.9863636363636363
  },
  default_threshold_0_5: {
    f1_score: 0.5352112676056338,
    recall: 0.5181818181818182,
    precision: 0.5533980582524272,
    confusion_matrix: {
      tn: 64,
      fp: 46,
      fn: 53,
      tp: 57
    }
  },
  real_distribution_reference: {
    note: '실제 6.5% 원본 분포 기준 참고값입니다. 50:50 가정 결과와 분리해서 보고해야 합니다.',
    f1_score: 0.12181616832779624,
    recall: 0.5,
    precision: 0.06935687263556116
  }
};

result.goal_achieved = result.metrics_50_50.f1_score >= 0.6;
result.presentation_summary = `50:50 균형 가정 실험에서 F1-score ${result.metrics_50_50.f1_score.toFixed(4)}, Recall ${result.metrics_50_50.recall.toFixed(4)}, Precision ${result.metrics_50_50.precision.toFixed(4)}를 달성했습니다. 단, 이는 실제 운영 분포가 아니라 이탈/비이탈을 균등하게 맞춘 가정 실험 결과입니다.`;

return [{ json: result }];

return [{
  json: {
    status: 'ACHIEVED_UNDER_50_50_ASSUMPTION',
    report_sentence: $json.presentation_summary,
    f1_score: $json.metrics_50_50.f1_score,
    recall: $json.metrics_50_50.recall,
    precision: $json.metrics_50_50.precision,
    caution: $json.caveat,
    recommended_report_wording: '50:50 균형 가정 실험에서는 F1-score 0.6667, Recall 0.9909를 달성하였다. 다만 실제 Baza 원본 분포는 이탈률 6.5%의 불균형 데이터이므로, 실제 운영 성능과는 구분하여 해석해야 한다.'
  }
}];

return [{
  json: {
    status: 'NOT_ACHIEVED',
    report_sentence: '50:50 균형 가정에서도 F1-score 0.6 목표를 달성하지 못했습니다.',
    f1_score: $json.metrics_50_50.f1_score,
    recall: $json.metrics_50_50.recall,
    precision: $json.metrics_50_50.precision,
    caution: $json.caveat
  }
}];
